sys_script_include.script:
var TimetableHelper = Class.create();
TimetableHelper.prototype = {
    initialize: function() {},

    /**
     * Main function called by Flow Designer
     */
    processTimetableRequest: function(classes, location, startDate, endDate, ritmSysID) {
        try {
            // 1. Fetch related Courses and Lecturers for the selected Classes
            var classDetails = this._getCourseAndLecturerData(classes);

            // 2. Fetch the Child Locations (Rooms) for the selected Location
            var roomDetails = this._getChildLocations(location);

            // 3. Prepare the Prompt for Gemini with strict JSON and attribute instructions
            var promptText = "You are an AI timetable generator. Create a university timetable based on the constraints below. " +
                             "You MUST return the response strictly in JSON format. " +
                             "Each entry in the timetable MUST include exactly these attributes: " +
                             "Date, Lecture Start time, Lecture End Time, Class, Lecturers, Courses.\n\n" +
                             "Constraints:\n" +
                             "- Term Duration: " + startDate + " to " + endDate + "\n" +
                             roomDetails + "\n" +
                             "- Class Details (Includes required Courses & Lecturers):\n" + classDetails;

            // 4. Call the Gemini API
            var rawJsonResponse = this._callGeminiAPI(promptText);

            if (rawJsonResponse) {
                // 5. Save the RAW JSON directly to the result table
                this._saveToResultTable(rawJsonResponse, ritmSysID);
            } else {
                gs.error("AUMS Error: Gemini API returned an empty response.");
            }

        } catch (ex) {
            gs.error("AUMS Error in processTimetableRequest: " + ex.message);
        }
    },

    /**
     * Queries the AUMS tables to get child rooms for the selected location.
     */
    _getChildLocations: function(locationSysId) {
        var roomList = [];

        // IMPORTANT: Update this to match your actual Location or Room table
        var grLocation = new GlideRecord('cmn_location'); 

        // Assuming 'parent' is the field that links a room to its building/campus
        grLocation.addQuery('parent', locationSysId); 
        grLocation.query();

        while (grLocation.next()) {
            roomList.push(grLocation.name.toString()); 
        }

        // Fallback in case the location has no children (e.g., they selected a specific room directly)
        if (roomList.length === 0) {
            return "- Available Rooms: " + locationSysId + " (Warning: No child rooms found)";
        }

        return "- Available Rooms for Scheduling: " + roomList.join(', ');
    },

    /**
     * Queries the AUMS tables to get courses and lecturers for the selected classes.
     */
    _getCourseAndLecturerData: function(classNames) {
        var dataString = "";

        var grCourse = new GlideRecord('x_595775_automat_0_courses'); // REPLACE with your actual mapping table
        grCourse.addEncodedQuery('u_classIN' + classNames); 
        grCourse.query();

        while (grCourse.next()) {
            dataString += "- Class: " + grCourse.u_class.getDisplayValue() + 
                          " | Course: " + grCourse.u_course_name.getDisplayValue() + 
                          " | Lecturer: " + grCourse.u_lecturer.getDisplayValue() + "\n";
        }

        if (dataString === "") {
            dataString = "- Selected Classes: " + classNames + " (No specific courses/lecturers found)\n";
        }

        return dataString;
    },

    /**
     * Handles the REST Message to Gemini
     */
    _callGeminiAPI: function(prompt) {
        try {
            var r = new sn_ws.RESTMessageV2('Gemini AI Integration', 'TIMETABLE'); 

            var body = {
                "contents": [{
                    "parts": [{
                        "text": prompt
                    }]
                }]
            };

            r.setRequestBody(JSON.stringify(body));
            var response = r.execute();
            var responseBody = response.getBody();
            var httpStatus = response.getStatusCode();

            if (httpStatus == 200) {
                return responseBody;
            } else {
                gs.error("AUMS API Call Failed with status " + httpStatus + ". Response: " + responseBody);
                return null;
            }
        } catch (ex) {
            gs.error("AUMS REST Call Exception: " + ex.message);
            return null;
        }
    },

    /**
     * Inserts the raw JSON result into your custom table
     */
    _saveToResultTable: function(rawJson, ritmID) {
        var grResult = new GlideRecord('x_595775_automat_0_timetable'); // REPLACE with your actual table name
        grResult.initialize();

        grResult.result = rawJson; 
        grResult.parent_request = ritmID; 

        var newSysID = grResult.insert();
        gs.info("AUMS: Raw JSON Timetable record created successfully: " + newSysID);
    },

    type: 'TimetableHelper'
};
